class Solution:
    def evaluateTree(self, root):
        def ev(node):
            if node.left is None and node.right is None:
                return node.val == 1
            vals = [ev(node.left), ev(node.right)]
            if node.val == 2:
                return any(vals)
            return all(vals)
        return ev(root)

