class Solution:
    def evaluateTree(self, root):
        if root.left is None and root.right is None:
            return bool(root.val)
        l = self.evaluateTree(root.left)
        r = self.evaluateTree(root.right)
        return (l or r) if root.val == 2 else (l and r)

